entities.schema:
{
  user_id: string,
  name: string,
  age: int,
  bio: string,
  photos: [string],  // S3 URLs
  location: { lat, lng },
  preferences: { min_age, max_age, max_distance_km, gender }
}

{
  swiper_id: string,
  swipee_id: string,
  direction: enum(LIKE|PASS),
  timestamp: ISO8601
}

{
  match_id: UUID,
  user1_id: string,
  user2_id: string,
  matched_at: timestamp
}
